  ('medical-tech-moex-11900', 'medical-tech', 'medical-tech-moex-102-bccd9a5a', 'sub-medical-tech-05', NULL, 'single_choice', '有關viridans streptococci之敘述，下列何者錯誤？', '["在sheep BAP上為不溶血或β-溶血的菌種", "部分菌株需CO 才能生長 2", "是人類上呼吸道、腸胃道、女性生殖道之正常菌群", "某些具有A、C、G群特異性抗原之菌種含有M protein，與致病力有關"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:16:44+00:00", "source_pdf_sha1": "0770013e9b2e", "answer_pdf_sha1": "a3e37902d519", "source_family": "moex-gov-tw", "moex": {"exam_code": "102100", "c": "311", "s": "44", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "微生物學與臨床微生物學（包括細菌與黴菌）", "year": "102", "exam_name": "102年第二次專技牙醫師分試藥師醫事檢驗師醫放師助產師物理治療師職能治療師呼吸治療師獸醫師考試", "original_question_number": 13, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
